#include<bits/stdc++.h>
using namespace std;
long double a[5050],dp[5050],ans[5050];
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
    }
    long double max1=0;
    for(int i=1;i<=n;i++)
    {
        dp[i]=1;
        for(int j=1;j<i;j++)
        {
            if(a[i]<a[j])
            {
                dp[i]=max(dp[i],dp[j]+1);
            }
        }
        max1=max(max1,dp[i]);
        for(int j=1;j<i;j++)
        {
            if(dp[i]==dp[j]&&a[i]==a[j])
            {
                ans[j]=0;
            }
            else if(dp[i]==dp[j]+1&&a[i]<a[j])
            {
                ans[i]+=ans[j];
            }
        }
        if(ans[i]==0)
        {
            ans[i]=1;
        }
    }
    long double res=0;
    for(int i=1;i<=n;i++)
    {
        if(dp[i]==max1)
        {
            res+=ans[i];
        }
    }
    cout<<fixed<<setprecision(0)<<max1<<' '<<res;
    return 0;
}
